using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 breaking change #1: Discriminator property renamed to "$type".
            // Preserve "Discriminator" so existing 500K documents remain readable
            // and direct SQL queries (WHERE c.Discriminator = 'Product') keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 breaking change #2: Id format changed from "EntityType|Key" to just "Key".
            // Existing documents have id = "Product|123". Override id generation to keep that format.
            entity.HasKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // EF Core 9 breaking change #3: HasIndex() now throws for Cosmos (non-relational).
            // Cosmos indexes are managed on the container, not via EF.
            // Removed: entity.HasIndex(p => p.Sku);
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = default!;
}

